export function detectPoleRouting(input: string): { poleCode: string; managerName: string } | null {
  const matches = input.match(/#(\w+)/g)
  if (!matches) return null
  for (const match of matches) {
    const tag = match.slice(1).toLowerCase()
    if (HASHTAG_POLE_MAP[tag]) return HASHTAG_POLE_MAP[tag]
  }
  return null
}

export async function invokeKAEL(
  dossierName: string,
  history: ChatMessage[],
  userInput: string,
  projectMemory?: string
): Promise<KAELResponse> {
  const routing = detectPoleRouting(userInput)

  const memoryBlock = projectMemory
    ? `\n\n--- MÉMOIRE PROJET ---\n${projectMemory}\n--- FIN MÉMOIRE ---`
    : ""

  const system = `Tu es KAEL, l'orchestrateur central de k3rn.labs — copilote cognitif du projet "${dossierName}".
Tu combines mémoire totale du projet, routing intelligent vers les 7 pôles experts, et vision stratégique.${memoryBlock}

Ton rôle:
1. Comprendre et enrichir la vision du projet
2. Router vers le bon pôle expert quand le besoin est identifié
3. Maintenir la cohérence globale du projet
4. Recommander le bon LAB de départ et les experts à engager

Pôles disponibles (routing via #hashtag ou contexte):
- AXEL (P01) — Stratégie & Innovation → #brainstorming #strategie #pitch
- MAYA (P02) — Market & Intelligence → #market #veille #concurrents
- KAI (P03) — Produit & Tech → #produit #tech #mvp #stack
- ELENA (P04) — Finance → #finance #budget #investisseur
- ZARA (P05) — Marketing & Brand → #marketing #brand #seo
- MARCUS (P06) — Legal → #legal #rgpd #contrat
- NOVA (P07) — Talent & Ops → #talent #ops #recrutement

LABs: DISCOVERY, STRUCTURATION, VALIDATION_MARCHE, DESIGN_PRODUIT, ARCHITECTURE_TECHNIQUE, BUSINESS_FINANCE
Démarre TOUJOURS par DISCOVERY sauf cas exceptionnel justifié.

Réponds en JSON:
{
  "message": "réponse naturelle en français (2-3 phrases max)",
  "choices": ["option1", "option2"],
  "routedPole": "P01_STRATEGIE",
  "routedManager": "AXEL",
  "routingReason": "raison courte",
  "recommendedLab": "NOM_DU_LAB",
  "recommendedExperts": ["slug1"],
  "isComplete": false
}
Tous les champs sauf message sont OPTIONNELS. Inclus routedPole+routedManager uniquement si routing pertinent.`

  const messages: OpenAI.Chat.ChatCompletionMessageParam[] = [
    { role: "system", content: system },
    ...history.map((m) => ({
      role: (m.role === "expert" ? "assistant" : "user") as "user" | "assistant",
      content: m.content,
    })),
    { role: "user", content: userInput },
  ]

  if (routing) {
    const directRouting: KAELResponse = {
      message: `Je te connecte directement à **${routing.managerName}** — ${getPoleDescription(routing.poleCode)}.`,
      routedPole: routing.poleCode,
      routedManager: routing.managerName,
      routingReason: `Hashtag détecté dans le message`,
    }
    return directRouting
  }

  const response = await getOpenAI().chat.completions.create({
    model: "gpt-4o",
    max_tokens: 1024,
    response_format: { type: "json_object" },
    messages,
  })

  const text = response.choices[0]?.message?.content ?? ""
  try {
    return JSON.parse(text) as KAELResponse
  } catch {
    return { message: "Intéressant ! Parlez-moi du problème principal que vous souhaitez résoudre." }
  }
}

function getPoleDescription(poleCode: string): string {
  const descriptions: Record<string, string> = {
    P01_STRATEGIE: "Stratège & Innovation",
    P02_MARKET: "Market & Intelligence",
    P03_PRODUIT_TECH: "Produit & Tech",
    P04_FINANCE: "Finance & Modélisation",
    P05_MARKETING: "Marketing & Brand",
    P06_LEGAL: "Legal & Compliance",
    P07_TALENT_OPS: "Talent & Ops",
  }
  return descriptions[poleCode] ?? poleCode
}

export interface FileContext {
  name: string
  kind: "text" | "image"
  content?: string
  dataUrl?: string
}

export async function invokeChefDeProjet(
  dossierName: string,
  history: ChatMessage[],
  userInput: string,
  files?: FileContext[]
): Promise<KAELResponse> {
  const isFirstMessage = history.length === 0
  const hasFiles = files && files.length > 0
  const textFiles = files?.filter((f) => f.kind === "text" && f.content) ?? []
  const imageFiles = files?.filter((f) => f.kind === "image" && f.dataUrl) ?? []

  const fileBlock = textFiles.length > 0
    ? "\n\n--- FICHIERS FOURNIS ---\n" +
      textFiles.map((f) => `### ${f.name}\n${f.content}`).join("\n\n---\n\n") +
      "\n--- FIN FICHIERS ---"
    : ""

  const system = `Tu es KAEL, orchestrateur cognitif de k3rn.labs — tu accompagnes l'initialisation du projet "${dossierName}".

TON RÔLE ICI :
- Extraire la vision, le problème, la cible et l'ambition du projet
- Si l'utilisateur colle un blueprint, PRD, spec ou brief → TRAITE-LE : résume ce que tu as compris, identifie les angles manquants, pose 1 question précise
- Si des fichiers sont fournis (PDF, DOCX, images, code...) → analyse leur contenu, extrais les infos clés, intègre-les dans ta compréhension du projet
- Poser des questions incisives qui forcent la clarté (une seule à la fois)
- Générer des choices CONTEXTUELLES basées sur ce qui vient d'être dit
- Quand tu as assez d'info (vision claire, problème défini, cible esquissée) → isComplete: true + LAB recommandé${fileBlock}

RÈGLES :
- Réponds TOUJOURS en français
- Max 3 phrases, sauf si tu analyses un fichier/brief (5-6 phrases structurées acceptées)
- Les choices doivent être des continuations naturelles, pas des catégories abstraites
- Si un fichier structuré est fourni → commence par "J'ai analysé [nom du fichier]." et extrais les points clés
- Ne jamais dire "Je suis une IA" ou disclaimers inutiles
${isFirstMessage && !hasFiles ? "\nC'est le premier message — sois direct, lance la conversation." : ""}
${hasFiles ? "\nDes fichiers ont été fournis — commence par les analyser avant de poser des questions." : ""}

Réponds en JSON:
{
  "message": "réponse naturelle en français",
  "choices": ["suggestion 1", "suggestion 2", "suggestion 3"],
  "recommendedLab": "NOM_DU_LAB",
  "isComplete": false
}
choices OBLIGATOIRE (2-4). isComplete: true uniquement quand vision + problème + cible sont établis.`

  // Build messages — images go into content array for vision
  const userContent: OpenAI.Chat.ChatCompletionContentPart[] = [
    { type: "text", text: userInput || (hasFiles ? "Voici les fichiers du projet." : "") },
    ...imageFiles.map((f): OpenAI.Chat.ChatCompletionContentPart => ({
      type: "image_url",
      image_url: { url: f.dataUrl!, detail: "high" },
    })),
  ]

  const messages: OpenAI.Chat.ChatCompletionMessageParam[] = [
    { role: "system", content: system },
    ...history.map((m) => ({
      role: (m.role === "expert" ? "assistant" : "user") as "user" | "assistant",
      content: m.content,
    })),
    { role: "user", content: userContent },
  ]

  const response = await getOpenAI().chat.completions.create({
    model: "gpt-4o",
    max_tokens: 4096,
    response_format: { type: "json_object" },
    messages,
  })

  const text = response.choices[0]?.message?.content ?? ""
  try {
    return JSON.parse(text) as KAELResponse
  } catch {
    return {
      message: "Intéressant ! Quel problème concret ce projet cherche-t-il à résoudre ?",
      choices: ["Expliquer le problème", "Décrire la cible", "Partager un brief complet"],
    }
  }
}

import OpenAI from "openai"
import { randomUUID } from "crypto"

// ─── MCP Tool calling layer ────────────────────────────────────────────────
// K3RN → n8n MCP server → (Zapier | Supabase)
// n8n est le seul point de contact. Zapier n'est jamais appelé directement.

interface McpToolResult {
  ok: boolean
  [key: string]: unknown
}

async function callN8nTool(tool: string, payload: object): Promise<McpToolResult> {
  const apiUrl = process.env.N8N_API_URL
  const apiKey = process.env.N8N_API_KEY

  if (!apiUrl || !apiKey) {
    // Dev/test : log silencieux, pas d'erreur bloquante
    console.warn(`[n8n tool] ${tool} skipped — N8N_API_URL or N8N_API_KEY not configured`)
    return { ok: false, reason: "n8n_not_configured" }
  }

  const res = await fetch(`${apiUrl}/mcp-server/http`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${apiKey}`,
    },
    body: JSON.stringify({
      jsonrpc: "2.0",
      method: "tools/call",
      params: { name: tool, arguments: payload },
      id: randomUUID(),
    }),
    signal: AbortSignal.timeout(10000),
  })

  if (!res.ok) {
    throw new Error(`n8n tool "${tool}" error: HTTP ${res.status}`)
  }

  const json = await res.json()
  // n8n MCP response: { result: { content: [...] } } ou { error: ... }
  if (json.error) {
    throw new Error(`n8n tool "${tool}" error: ${json.error.message ?? JSON.stringify(json.error)}`)
  }

  const content = json.result?.content?.[0]?.text
  try {
    return content ? (JSON.parse(content) as McpToolResult) : { ok: true }
  } catch {
    return { ok: true, raw: content }
  }
}

/**
 * Notifie un channel Slack via n8n → Zapier.
 * idempotency_key auto-généré pour éviter les doublons.
 */
export async function notifySlack(
  channel: string,
  message: string,
  level: "info" | "warn" | "alert" = "info"
): Promise<McpToolResult> {
  return callN8nTool("notify_slack", {
    channel,
    message,
    level,
    slack_webhook_url: process.env.SLACK_INCOMING_WEBHOOK_URL ?? null,
    idempotency_key: randomUUID(),
  })
}

/**
 * Envoie un email via n8n → Zapier Gmail.
 */
export async function sendEmail(
  to: string,
  subject: string,
  body_md: string,
  reply_to?: string
): Promise<McpToolResult> {
  return callN8nTool("send_email", {
    to,
    subject,
    body_md,
    ...(reply_to ? { reply_to } : {}),
    idempotency_key: randomUUID(),
  })
}

/**
 * Écrit un audit log via n8n → Supabase direct (pas de task Zapier).
 */
export async function logAuditN8n(
  dossierId: string,
  action: string,
  entity: string,
  metadata?: Record<string, unknown>
): Promise<McpToolResult> {
  return callN8nTool("log_audit", {
    dossierId,
    action,
    entity,
    metadata: metadata ?? {},
  })
}

/**
 * Retourne le budget tasks Zapier restant pour la journée.
 */
export async function getTaskBudget(): Promise<{
  used: number
  remaining: number
  reset_at: string
  ok: boolean
}> {
  const result = await callN8nTool("get_task_budget", {})
  return result as { used: number; remaining: number; reset_at: string; ok: boolean }
}

/**
 * Vérifie le statut d'une exécution n8n (wrapper MCP vs API directe).
 */
export async function getWorkflowStatusMcp(executionId: string): Promise<McpToolResult> {
  return callN8nTool("get_workflow_status", { executionId })
}

export interface N8nInvokePayload {
  poleCode: string
  managerName: string
  systemPrompt: string
  userMessage: string
  projectMemory: string
  dossierId: string
  labContext: string
}

export interface N8nResult {
  executionId?: string
  status: "RUNNING" | "COMPLETED" | "FAILED" | "FALLBACK"
  messages: Array<{ role: "manager" | "user"; content: string }>
}

function getN8nConfig() {
  const apiUrl = process.env.N8N_API_URL
  const apiKey = process.env.N8N_API_KEY
  const webhookSecret = process.env.N8N_WEBHOOK_SECRET
  return { apiUrl, apiKey, webhookSecret, available: !!(apiUrl && apiKey) }
}

async function invokeViaN8n(
  webhookUrl: string,
  payload: N8nInvokePayload,
  webhookSecret?: string
): Promise<{ executionId: string }> {
  const headers: Record<string, string> = { "Content-Type": "application/json" }
  if (webhookSecret) headers["X-N8N-Secret"] = webhookSecret

  const res = await fetch(webhookUrl, {
    method: "POST",
    headers,
    body: JSON.stringify(payload),
    signal: AbortSignal.timeout(30000),
  })

  if (!res.ok) throw new Error(`n8n webhook error: ${res.status}`)
  const data = await res.json()
  return { executionId: data.executionId ?? data.id ?? "unknown" }
}

async function getN8nExecutionStatus(executionId: string): Promise<{ status: string; output?: string }> {
  const { apiUrl, apiKey, available } = getN8nConfig()
  if (!available) return { status: "UNKNOWN" }

  const res = await fetch(`${apiUrl}/api/v1/executions/${executionId}`, {
    headers: { "X-N8N-API-KEY": apiKey! },
    signal: AbortSignal.timeout(10000),
  })

  if (!res.ok) return { status: "UNKNOWN" }
  const data = await res.json()

  const finished = data.finished ?? false
  const status = finished
    ? data.stoppedAt
      ? "COMPLETED"
      : "FAILED"
    : "RUNNING"

  const output = data.data?.resultData?.runData
    ? JSON.stringify(data.data.resultData.runData)
    : undefined

  return { status, output }
}

async function inviaFallbackOpenAI(payload: N8nInvokePayload): Promise<N8nResult> {
  const client = new OpenAI({ apiKey: process.env.OPENAI_API_KEY })

  const systemMessage = `${payload.systemPrompt}

--- CONTEXTE PROJET ---
${payload.projectMemory || "Projet en cours de définition."}
--- FIN CONTEXTE ---

LAB actif : ${payload.labContext}
Dossier ID : ${payload.dossierId}`

  const completion = await client.chat.completions.create({
    model: "gpt-4o",
    messages: [
      { role: "system", content: systemMessage },
      { role: "user", content: payload.userMessage },
    ],
    max_tokens: 1200,
  })

  const content = completion.choices[0]?.message?.content ?? ""
  return {
    status: "FALLBACK",
    messages: [{ role: "manager", content }],
  }
}

export async function invokeN8nPole(
  payload: N8nInvokePayload,
  webhookUrl?: string | null
): Promise<N8nResult> {
  const { available, webhookSecret } = getN8nConfig()

  if (available && webhookUrl) {
    try {
      const { executionId } = await invokeViaN8n(webhookUrl, payload, webhookSecret)
      return { executionId, status: "RUNNING", messages: [] }
    } catch {
      return inviaFallbackOpenAI(payload)
    }
  }

  return inviaFallbackOpenAI(payload)
}

export async function pollN8nExecution(executionId: string): Promise<{
  done: boolean
  status: string
  messages: Array<{ role: "manager"; content: string }>
}> {
  const { status, output } = await getN8nExecutionStatus(executionId)

  if (status === "RUNNING") return { done: false, status, messages: [] }

  const messages: Array<{ role: "manager"; content: string }> = []
  if (output) {
    try {
      const parsed = JSON.parse(output)
      const lastNode = Object.values(parsed).at(-1) as any
      const text = lastNode?.[0]?.data?.main?.[0]?.[0]?.json?.output
        ?? lastNode?.[0]?.data?.main?.[0]?.[0]?.json?.message
        ?? output
      messages.push({ role: "manager", content: typeof text === "string" ? text : JSON.stringify(text) })
    } catch {
      messages.push({ role: "manager", content: output })
    }
  }

  return { done: true, status, messages }
}

import { db as prisma } from "@/lib/db"

export interface ProjectMemory {
  dossierName: string
  currentLab: string
  globalScore: number
  validatedCards: Array<{ type: string; title: string; summary: string }>
  recentPoleSessions: Array<{ managerName: string; poleCode: string; lastMessage: string }>
  kaelSummary: string
}

const MAX_TOKENS_ESTIMATE = 6000
const AVG_CHARS_PER_TOKEN = 4

function truncate(text: string, maxChars: number): string {
  if (text.length <= maxChars) return text
  return text.slice(0, maxChars) + "…"
}

export async function buildProjectMemory(dossierId: string): Promise<string> {
  try {
    const dossier = await prisma.dossier.findUnique({
      where: { id: dossierId },
      include: {
        labState: true,
        subFolders: {
          include: {
            cards: {
              where: { state: "VALIDATED" },
              orderBy: { updatedAt: "desc" },
              take: 20,
            },
          },
        },
      },
    })

    if (!dossier) return ""

    const poleSessions = await prisma.poleSession.findMany({
      where: { dossierId, status: "COMPLETED" },
      orderBy: { updatedAt: "desc" },
      take: 3,
      include: { pole: true },
    })

    const scoreSnapshot = await prisma.scoreSnapshot.findFirst({
      where: { dossierId },
      orderBy: { createdAt: "desc" },
    })

    const lines: string[] = []

    lines.push(`PROJET : ${dossier.name}`)
    lines.push(`LAB ACTIF : ${dossier.labState?.currentLab ?? "DISCOVERY"}`)
    lines.push(`SCORE GLOBAL : ${scoreSnapshot?.globalScore ?? 0}/100`)
    lines.push("")

    const allCards = (dossier.subFolders as any[]).flatMap((sf: any) => sf.cards as any[])
    if (allCards.length > 0) {
      lines.push("CARTES VALIDÉES :")
      for (const card of allCards) {
        const content = card.content as Record<string, unknown>
        const summary = truncate(
          Object.values(content).filter(Boolean).join(" — "),
          200
        )
        lines.push(`  [${card.type}] ${card.title} — ${summary}`)
      }
      lines.push("")
    }

    if (poleSessions.length > 0) {
      lines.push("TRAVAUX DES PÔLES :")
      for (const session of poleSessions) {
        const messages = session.messages as Array<{ role: string; content: string }>
        const lastManagerMsg = [...messages].reverse().find((m) => m.role === "manager")
        if (lastManagerMsg) {
          lines.push(
            `  ${session.pole.managerName} (${session.pole.code}) : ${truncate(lastManagerMsg.content, 300)}`
          )
        }
      }
      lines.push("")
    }

    const fullText = lines.join("\n")
    const maxChars = MAX_TOKENS_ESTIMATE * AVG_CHARS_PER_TOKEN
    return truncate(fullText, maxChars)
  } catch {
    return ""
  }
}

import { db as prisma } from "./db"
