import { createServerClient } from "@supabase/ssr"
import { cookies } from "next/headers"
import { NextRequest } from "next/server"
import { db as prisma } from "./db"
import type { UserRole } from "@prisma/client"

export interface SessionUser {
  userId: string
  email: string
  role: UserRole
}

export async function verifySession(req?: NextRequest): Promise<SessionUser | null> {
  try {
    const cookieStore = await cookies()
    const supabase = createServerClient(
      process.env.NEXT_PUBLIC_SUPABASE_URL!,
      process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
      {
        cookies: {
          getAll() {
            return cookieStore.getAll()
          },
          setAll(cookiesToSet) {
            try {
              cookiesToSet.forEach(({ name, value, options }) =>
                cookieStore.set(name, value, options)
              )
            } catch {}
          },
        },
      }
    )

    const { data: { user }, error } = await supabase.auth.getUser()
    if (error || !user) return null

    let dbUser = await prisma.user.findUnique({ where: { id: user.id } })
    if (!dbUser) {
      dbUser = await prisma.user.create({
        data: { id: user.id, email: user.email!, role: "OWNER" },
      })
    }

    return { userId: dbUser.id, email: dbUser.email, role: dbUser.role }
  } catch {
    return null
  }
}

export function requireAuth(session: SessionUser | null): SessionUser {
  if (!session) throw new Error("UNAUTHORIZED")
  return session
}

export function requireRole(session: SessionUser, role: UserRole): SessionUser {
  const hierarchy: Record<UserRole, number> = { OWNER: 3, COLLABORATOR: 2, VIEWER: 1 }
  if (hierarchy[session.role] < hierarchy[role]) throw new Error("FORBIDDEN")
  return session
}

import { NextRequest } from "next/server"
import { verifySession } from "@/lib/auth"
import { db as prisma } from "@/lib/db"
import { apiError, apiSuccess } from "@/lib/validate"
import { createAuditLog } from "@/lib/audit"
import { LAB_CONDITIONS, getLabOrder } from "@/lib/lab-conditions"
import { broadcastToChannel } from "@/lib/realtime"

export async function POST(req: NextRequest, { params }: { params: Promise<{ id: string }> }) {
  const session = await verifySession()
  if (!session) return apiError("Unauthorized", 401)

  const { id } = await params
  const dossier = await prisma.dossier.findFirst({
    where: { id, ownerId: session.userId },
    include: { labState: true },
  })
  if (!dossier) return apiError("Dossier not found", 404)
  if (!dossier.labState) return apiError("No LAB state", 422)

  const currentLab = dossier.labState.currentLab
  const conditions = (LAB_CONDITIONS as any)[currentLab]
  if (!conditions.nextLab) return apiError("Already at final LAB", 422)

  const subFolders = await prisma.subFolder.findMany({
    where: { dossierId: id },
    include: { cards: { where: { state: "VALIDATED" } } },
  })
  const validatedCardTypes = subFolders.flatMap((sf: any) => sf.cards.map((c: any) => c.type))
  const missingCards = conditions.requiredValidatedCardTypes.filter(
    (t: any) => !validatedCardTypes.includes(t)
  )
  if (missingCards.length > 0) {
    return apiError(`Missing required cards: ${missingCards.join(", ")}`, 422)
  }

  const blockingExperts = await prisma.expertSession.findMany({
    where: { dossierId: id, status: { notIn: ["VALIDATED", "REJECTED"] } },
    include: { expert: true },
  })
  const blockers = blockingExperts.filter((s: any) => s.expert.blocksLabTransition)
  if (blockers.length > 0) {
    return apiError(`Blocking experts pending: ${blockers.map((b: any) => b.expert.name).join(", ")}`, 422)
  }

  const updated = await prisma.labState.update({
    where: { dossierId: id },
    data: { currentLab: conditions.nextLab, transitionAllowed: false },
  })

  await prisma.dossier.update({ where: { id }, data: { macroState: "LAB_TRANSITION" } })

  await createAuditLog({
    userId: session.userId,
    dossierId: id,
    action: "LAB_TRANSITION",
    entity: "LabState",
    entityId: updated.id,
    metadata: { from: currentLab, to: conditions.nextLab },
  })

  await broadcastToChannel(id, "lab", { from: currentLab, to: conditions.nextLab })

  return apiSuccess(updated)
}

import { createSupabaseClient } from "./supabase"

export type RealtimeChannel = "canvas" | "score" | "lab"

export function subscribeToChannel(
  dossierId: string,
  channel: RealtimeChannel,
  onUpdate: (payload: unknown) => void
) {
  const supabase = createSupabaseClient()
  const channelName = `dossier:${dossierId}:${channel}`

  const sub = supabase
    .channel(channelName)
    .on("broadcast", { event: "update" }, (payload) => onUpdate(payload))
    .subscribe()

  return () => {
    supabase.removeChannel(sub)
  }
}

export async function broadcastToChannel(
  dossierId: string,
  channel: RealtimeChannel,
  payload: unknown
) {
  const { createSupabaseAdmin } = await import("./supabase")
  const supabase = createSupabaseAdmin()
  const channelName = `dossier:${dossierId}:${channel}`

  await supabase.channel(channelName).send({
    type: "broadcast",
    event: "update",
    payload,
  })
}

import { NextRequest } from "next/server"
import { verifySession } from "@/lib/auth"
import { apiError, apiSuccess } from "@/lib/validate"

const TEXT_EXTENSIONS = new Set([
  "txt", "md", "mdx", "csv", "json", "jsonl", "yaml", "yml",
  "ts", "tsx", "js", "jsx", "py", "rb", "go", "rs", "java",
  "html", "htm", "css", "scss", "sql", "xml", "toml", "env",
  "sh", "bash", "zsh", "fish", "conf", "ini", "log",
])

function ext(filename: string) {
  return filename.split(".").pop()?.toLowerCase() ?? ""
}

async function extractPdf(buffer: Buffer): Promise<string> {
  // eslint-disable-next-line @typescript-eslint/no-require-imports
  const pdfParse = require("pdf-parse") as (buf: Buffer) => Promise<{ text: string }>
  const data = await pdfParse(buffer)
  return data.text?.trim() ?? ""
}

async function extractDocx(buffer: Buffer): Promise<string> {
  const mammoth = (await import("mammoth")).default
  const result = await mammoth.extractRawText({ buffer })
  return result.value?.trim() ?? ""
}

async function extractXlsx(buffer: Buffer): Promise<string> {
  const XLSX = await import("xlsx")
  const wb = XLSX.read(buffer, { type: "buffer" })
  const lines: string[] = []
  for (const sheetName of wb.SheetNames) {
    const ws = wb.Sheets[sheetName]
    const csv = XLSX.utils.sheet_to_csv(ws)
    if (csv.trim()) {
      lines.push(`## Feuille: ${sheetName}`)
      lines.push(csv.trim())
    }
  }
  return lines.join("\n\n")
}

export async function POST(req: NextRequest) {
  const session = await verifySession()
  if (!session) return apiError("Unauthorized", 401)

  const formData = await req.formData()
  const file = formData.get("file") as File | null
  if (!file) return apiError("No file provided", 400)

  const maxSize = 20 * 1024 * 1024 // 20 MB
  if (file.size > maxSize) return apiError("File too large (max 20 MB)", 400)

  const filename = file.name
  const mimeType = file.type
  const fileExt = ext(filename)
  const buffer = Buffer.from(await file.arrayBuffer())

  try {
    let content = ""
    let method = ""

    // Images → return as base64 data URL for vision
    if (mimeType.startsWith("image/")) {
      const base64 = buffer.toString("base64")
      const dataUrl = `data:${mimeType};base64,${base64}`
      return apiSuccess({ filename, type: "image", dataUrl, content: null })
    }

    // PDF
    if (mimeType === "application/pdf" || fileExt === "pdf") {
      content = await extractPdf(buffer)
      method = "pdf-parse"

    // DOCX / Word
    } else if (
      mimeType === "application/vnd.openxmlformats-officedocument.wordprocessingml.document" ||
      fileExt === "docx"
    ) {
      content = await extractDocx(buffer)
      method = "mammoth"

    // XLSX / Excel
    } else if (
      mimeType === "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet" ||
      mimeType === "application/vnd.ms-excel" ||
      fileExt === "xlsx" || fileExt === "xls" || fileExt === "csv"
    ) {
      content = fileExt === "csv"
        ? buffer.toString("utf-8")
        : await extractXlsx(buffer)
      method = "xlsx"

    // Plain text / code
    } else if (TEXT_EXTENSIONS.has(fileExt) || mimeType.startsWith("text/")) {
      content = buffer.toString("utf-8")
      method = "text"

    } else {
      return apiError(`Unsupported file type: ${mimeType || fileExt}`, 415)
    }

    // Truncate if too large (max ~50k chars ≈ ~12k tokens)
    const truncated = content.length > 50000
    if (truncated) content = content.slice(0, 50000) + "\n\n[… contenu tronqué à 50 000 caractères]"

    return apiSuccess({
      filename,
      type: "text",
      content,
      method,
      chars: content.length,
      truncated,
    })
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err)
    return apiError(`Extraction failed: ${msg}`, 500)
  }
}
